```solidity
pragma solidity ^0.8.20;

contract CollectibleSale {
    address public owner;
    uint256 public maxSupply;
    uint256 public price;
    uint256 public totalMinted;
    bool public saleEnded;
    mapping(address => uint256) public balances;

    event Buy(address indexed buyer, uint256 amount);
    event PriceChanged(uint256 newPrice);
    event SaleEnded(bool ended);

    constructor(uint256 maxSupply_, uint256 price_) {
        require(maxSupply_ > 0, "Max supply must be greater than zero");
        require(price_ > 0, "Price must be greater than zero");
        owner = msg.sender;
        maxSupply = maxSupply_;
        price = price_;
        saleEnded = false;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the owner");
        _;
    }

    function buy(uint256 amount) external payable {
        require(!saleEnded, "Sale has ended");
        require(amount > 0 && amount <= 10, "Amount must be between 1 and 10");
        require(totalMinted + amount <= maxSupply, "Exceeds max supply");
        require(msg.value == amount * price, "Incorrect payment amount");

        unchecked {
            uint256 newBalance = balances[msg.sender] + amount;
            balances[msg.sender] = newBalance;
            totalMinted += amount;
        }

        if (totalMinted >= maxSupply) {
            saleEnded = true;
            emit SaleEnded(true);
        } else {
            emit SaleEnded(false);
        }

        emit Buy(msg.sender, amount);
    }

    function setPrice(uint256 newPrice) external onlyOwner {
        require(newPrice > 0, "New price must be greater than zero");
        price = newPrice;
        emit PriceChanged(newPrice);
    }

    function setSaleEnded(bool _ended) external onlyOwner {
        saleEnded = _ended;
        emit SaleEnded(_ended);
    }

    function withdraw() external onlyOwner {
        require(address(this).balance > 0, "No funds to withdraw");
        payable(owner).transfer(address(this).balance);
    }
}
```

